fn lcp_between(s1: &str, s2: &str) -> usize {
    let min_len = s1.len().min(s2.len());
    let s1_bytes = s1.as_bytes();
    let s2_bytes = s2.as_bytes();
    let mut i = 0;
    while i < min_len {
        if s1_bytes[i] != s2_bytes[i] {
            return i;
        }
        i += 1;
    }
    min_len
}

pub fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    if n == 1 {
        return vec![0];
    }

    let mut lcp = vec![0; n-1];
    for i in 0..n-1 {
        lcp[i] = lcp_between(&words[i], &words[i+1]);
    }

    let mut left_max = vec![0; n-1];
    left_max[0] = lcp[0] as i64;
    for i in 1..n-1 {
        left_max[i] = left_max[i-1].max(lcp[i] as i64);
    }

    let mut right_max = vec![0; n-1];
    right_max[n-2] = lcp[n-2] as i64;
    for i in (0..n-2).rev() {
        right_max[i] = right_max[i+1].max(lcp[i] as i64);
    }

    let mut answer = vec![0; n];
    for k in 0..n {
        let candidate1 = if k >= 2 {
            left_max[k-2]
        } else {
            0
        };

        let candidate2 = if k >= 1 && k < n-1 {
            lcp_between(&words[k-1], &words[k+1]) as i64
        } else {
            0
        };

        let candidate3 = if k <= n-3 {
            right_max[k+1]
        } else {
            0
        };

        answer[k] = candidate1.max(candidate2).max(candidate3);
    }

    answer
}
```

### Explanation
1. **LCP Calculation**: The `lcp_between` function computes the length of the longest common prefix between two strings by comparing characters up to the minimum length of the two strings.
2. **Initial Setup**: For a single-element array, the result is trivially `[0]` since no adjacent pairs exist after removal.
3. **LCP Array Construction**: For each adjacent pair in the original array, the LCP length is precomputed and stored in the `lcp` array.
4. **Prefix and Suffix Arrays**: The `left_max` array stores the maximum LCP value from the start up to each index, while `right_max` stores the maximum LCP value from each index to the end.
5. **Processing Removals**: For each index `k`:
   - **Left Segment**: If `k >= 2`, the maximum LCP in the segment `[0, k-2]` is retrieved from `left_max`.
   - **New Bridge Pair**: If `k` is not at the boundaries, the LCP between `words[k-1]` and `words[k+1]` is computed.
   - **Right Segment**: If `k <= n-3`, the maximum LCP in the segment `[k+1, n-2]` is retrieved from `right_max`.
6. **Result Compilation**: The result for each `k` is the maximum of the three segments, ensuring efficient computation without redundant operations.

This approach efficiently handles the constraints by leveraging precomputed values, reducing the overall complexity and ensuring optimal performance.

